function mergeInvoiceContext(base, text) {
  const context = { ...initialInvoiceContext(), ...(base || {}) };
  const fields = parseTemplateFields(text);
  const clientQuery = extractClientQuery(text);
  const numbered = detectNumberedLineItems(text);
  const implicit = numbered.length ? [] : detectImplicitLineItems(text);
  const lineItems = numbered.length ? numbered : implicit;
  if (clientQuery) context.client_query = clientQuery;
  if (lineItems.length > 1) {
    context.line_items = lineItems;
    context.work_text = null;
    context.amount = null;
    context.tax_mode = context.tax_mode || "UNKNOWN";
    context.operation_type = "MIXTO";
  } else {
    const extractedWork = fields.trabajo || extractWorkText(text);
    if (fields.trabajo || (extractedWork && looksLikeActivityLine(extractedWork))) context.work_text = extractedWork;
    const amount = extractAmount(fields.monto || text);
    if (amount) context.amount = amount;
    const taxMode = detectTaxMode(fields.iva || text);
    if (taxMode !== "UNKNOWN") context.tax_mode = taxMode;
    const op = detectOperationType(fields.tipo || text);
    if (op) context.operation_type = op;
    if (lineItems.length) context.line_items = lineItems;
  }
  context.original_text = [context.original_text, text].filter(Boolean).join("\n").trim();
  return context;
}

